update `student_feature`
student_id = #{studentId}, course_id = #{courseId}, attendance_count = #{attendanceCount}, attendance_rate = #{attendanceRate}, homework_submit_rate = #{homeworkSubmitRate}, homework_avg_score = #{homeworkAvgScore}, exam_avg_score = #{examAvgScore}, earned_credit = #{earnedCredit}, gpa = #{gpa}, missing_homework_count = #{missingHomeworkCount}, absent_exam_count = #{absentExamCount}, recent_risk_trend = #{recentRiskTrend}, feature_date = #{featureDate}, create_time = #{createTime},
where id = #{id}
